        .find_map(|cmdline| {
            FS_CONTEXT.lock().resolve(cmdline[0]).ok()
                .map(|loc| (cmdline, loc))
        })
        .expect("Failed to resolve executable path");

    // 3. еҲӣе»әз”ЁжҲ·ең°еқҖз©әй—ҙ
